package ratelimiter

import (
	"sync"
	"time"
)

// fixedWindowLimiter implements a per-key fixed window rate limiter.
// It tracks request counts for each key within discrete time windows.
// The algorithm follows the approach described in APPROACH.md.
type fixedWindowLimiter struct {
	cfg   Config
	clock Clock

	mu    sync.RWMutex
	// state maps a key to its current window start time and request count.
	state map[string]*keyState
}

type keyState struct {
	windowStart time.Time
	count       int
}

// newLimiter creates a new limiter instance. If clock is nil, a real‑time
// clock is used. If Burst is zero, it defaults to Rate.
func newLimiter(cfg Config, clock Clock) Limiter {
	if cfg.Burst <= 0 {
		cfg.Burst = cfg.Rate
	}
	if clock == nil {
		clock = realClock{}
	}
	return &fixedWindowLimiter{
		cfg:   cfg,
		clock: clock,
		state: make(map[string]*keyState),
	}
}

// realClock implements Clock using the standard time package.
type realClock struct{}

func (realClock) Now() time.Time { return time.Now() }

// windowStart returns the start of the fixed window that contains t.
// Windows are aligned to multiples of cfg.Window since the Unix epoch.
func (l *fixedWindowLimiter) windowStart(t time.Time) time.Time {
	if l.cfg.Window <= 0 {
		return time.Time{}
	}
	elapsed := t.Sub(time.Unix(0, 0))
	idx := elapsed / l.cfg.Window
	return time.Unix(0, 0).Add(idx * l.cfg.Window)
}

// Allow implements Limiter.Allow.
// It permits a request if the count for the current window is below the
// allowed limit (Rate or Burst, whichever is larger).
func (l *fixedWindowLimiter) Allow(key string) bool {
	now := l.clock.Now()
	win := l.windowStart(now)

	l.mu.Lock()
	defer l.mu.Unlock()

	ks, ok := l.state[key]
	if !ok {
		ks = &keyState{windowStart: win}
		l.state[key] = ks
	}

	// If we have moved into a new window, reset count.
	if !ks.windowStart.Equal(win) {
		ks.windowStart = win
		ks.count = 0
	}

	limit := l.cfg.Rate
	if l.cfg.Burst > limit {
		limit = l.cfg.Burst
	}

	if ks.count < limit {
		ks.count++
		return true
	}
	return false
}

// Reset clears any stored state for the given key.
func (l *fixedWindowLimiter) Reset(key string) {
	l.mu.Lock()
	defer l.mu.Unlock()
	delete(l.state, key)
}
EOF
