package ratelimiter

import (
	"sync"
	"time"
)

// tokenBucketLimiter implements a per-key token bucket rate limiter.
// It follows the approach described in APPROACH.md but uses a token bucket
// to correctly handle Burst semantics across windows.
type tokenBucketLimiter struct {
	cfg   Config
	clock Clock

	mu    sync.RWMutex
	// state maps a key to its bucket.
	state map[string]*bucket
}

type bucket struct {
	tokens      int
	lastRefill  time.Time
}

// newLimiter creates a new limiter. If clock is nil a real clock is used.
// If Burst == 0 it defaults to Rate.
func newLimiter(cfg Config, clock Clock) Limiter {
	if cfg.Burst <= 0 {
		cfg.Burst = cfg.Rate
	}
	if clock == nil {
		clock = realClock{}
	}
	return &tokenBucketLimiter{
		cfg:   cfg,
		clock: clock,
		state: make(map[string]*bucket),
	}
}

// realClock implements Clock using time.Now().
type realClock struct{}

func (realClock) Now() time.Time { return time.Now() }

// refill adds tokens based on elapsed time.
func (l *tokenBucketLimiter) refill(b *bucket, now time.Time) {
	if l.cfg.Window <= 0 {
		// No window defined: treat as infinite capacity.
		b.tokens = l.cfg.Burst
		b.lastRefill = now
		return
	}
	elapsed := now.Sub(b.lastRefill)
	if elapsed < l.cfg.Window {
		return
	}
	// Number of whole windows that have passed.
	windows := int(elapsed / l.cfg.Window)
	add := windows * l.cfg.Rate
	if add > 0 {
		b.tokens += add
		if b.tokens > l.cfg.Burst {
			b.tokens = l.cfg.Burst
		}
		// Move lastRefill forward by whole windows.
		b.lastRefill = b.lastRefill.Add(time.Duration(windows) * l.cfg.Window)
	}
}

// Allow implements Limiter.Allow.
func (l *tokenBucketLimiter) Allow(key string) bool {
	now := l.clock.Now()

	l.mu.Lock()
	defer l.mu.Unlock()

	b, ok := l.state[key]
	if !ok {
		b = &bucket{
			tokens:     l.cfg.Burst, // start full burst capacity
			lastRefill: now,
		}
		l.state[key] = b
	}

	// Refill tokens based on elapsed windows.
	l.refill(b, now)

	if b.tokens > 0 {
		b.tokens--
		return true
	}
	return false
}

// Reset clears the bucket for the given key.
func (l *tokenBucketLimiter) Reset(key string) {
	l.mu.Lock()
	defer l.mu.Unlock()
	delete(l.state, key)
}
EOF
